@startuml
title Facade 패턴(김동석)
header https://github.com/bluedskim/javaDesignPatterns
footer 작성시각 2026.06.02 20:32

skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor Black
  ArrowColor Black
}

skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeIBackgroundColor #D1C4E9

class "ShapeMakerTest" as ShapeMakerTest {
  void ShapeMakerFacadeTest()
}

class "ShapeMaker" as ShapeMaker {
  String drawAllShape()
}

interface "Shape" as Shape {
  String draw()
}

class "Circle" as Circle {
  String draw()
}

class "Rectangle" as Rectangle {
  String draw()
}

class "Square" as Square {
  String draw()
}

ShapeMakerTest --> ShapeMaker
ShapeMaker --> Shape
Circle ..|> Shape
Rectangle ..|> Shape
Square ..|> Shape

@enduml
